// Dark Star Consulting Footer Badge Component (Sleek Compact Edition)
// Automatically injects an understated Dark Star Consulting footer badge at the bottom of the page.

(function() {
  function initDarkStarFooter() {
    if (document.getElementById('darkstar-footer-container')) return;

    const style = document.createElement('style');
    style.id = 'darkstar-footer-styles';
    style.textContent = `
      #darkstar-footer-container {
        display: flex;
        justify-content: center;
        align-items: center;
        width: 100%;
        padding: 24px 16px 20px 16px;
        box-sizing: border-box;
        background: transparent;
        margin-top: auto;
      }

      .darkstar-badge-link {
        text-decoration: none;
        color: inherit;
        display: inline-block;
      }

      .darkstar-badge {
        display: inline-flex;
        align-items: center;
        gap: 12px;
        background: #ffffff;
        padding: 6px 18px 6px 14px;
        border-radius: 9999px;
        border: 1px solid rgba(0, 0, 0, 0.08);
        box-shadow: 0 4px 16px rgba(0, 0, 0, 0.04), 0 1px 3px rgba(0, 0, 0, 0.02);
        font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        color: #111827;
        transition: transform 0.25s cubic-bezier(0.16, 1, 0.3, 1), box-shadow 0.25s cubic-bezier(0.16, 1, 0.3, 1);
        cursor: pointer;
      }

      .darkstar-badge:hover {
        transform: translateY(-1.5px);
        box-shadow: 0 8px 20px rgba(0, 0, 0, 0.08);
      }

      .darkstar-badge-logo {
        display: flex;
        align-items: center;
        justify-content: center;
        width: 32px;
        height: 32px;
        flex-shrink: 0;
      }

      .darkstar-badge-logo img {
        width: 100%;
        height: 100%;
        object-fit: contain;
      }

      .darkstar-badge-divider {
        width: 1px;
        height: 24px;
        background-color: #e5e7eb;
        flex-shrink: 0;
      }

      .darkstar-badge-text {
        display: flex;
        flex-direction: column;
        align-items: flex-start;
        justify-content: center;
        line-height: 1.1;
      }

      .darkstar-by {
        font-size: 10px;
        font-weight: 400;
        color: #6b7280;
        letter-spacing: 0.02em;
      }

      .darkstar-brand {
        font-size: 13.5px;
        font-weight: 800;
        letter-spacing: 0.09em;
        color: #111827;
        margin-top: 1px;
        margin-bottom: 1.5px;
        font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      }

      .darkstar-sub-flourish {
        display: flex;
        align-items: center;
        gap: 4px;
        width: 100%;
      }

      .darkstar-sub-flourish .flourish-line {
        flex: 1;
        height: 1px;
        background-color: #9ca3af;
      }

      .darkstar-sub-flourish .flourish-dot {
        width: 2.5px;
        height: 2.5px;
        border-radius: 50%;
        background-color: #9ca3af;
      }

      .darkstar-sub {
        font-size: 7.5px;
        font-weight: 600;
        letter-spacing: 0.26em;
        color: #4b5563;
        text-transform: uppercase;
        padding: 0 1px;
      }

      @media (max-width: 640px) {
        #darkstar-footer-container {
          padding: 16px 12px 14px 12px;
        }
        .darkstar-badge {
          padding: 5px 14px 5px 10px;
          gap: 10px;
        }
        .darkstar-badge-logo {
          width: 26px;
          height: 26px;
        }
        .darkstar-badge-divider {
          height: 20px;
        }
        .darkstar-by {
          font-size: 9px;
        }
        .darkstar-brand {
          font-size: 11.5px;
        }
        .darkstar-sub {
          font-size: 6.5px;
        }
      }
    `;
    document.head.appendChild(style);

    const container = document.createElement('footer');
    container.id = 'darkstar-footer-container';

    container.innerHTML = `
      <a href="https://darkstarconsulting.com" target="_blank" rel="noopener noreferrer" class="darkstar-badge-link" aria-label="Website by Dark Star Consulting">
        <div class="darkstar-badge">
          <div class="darkstar-badge-logo">
            <img src="data:image/png;base64," alt="Dark Star Consulting Logo" />
          </div>
          <div class="darkstar-badge-divider"></div>
          <div class="darkstar-badge-text">
            <span class="darkstar-by">Website by</span>
            <span class="darkstar-brand">DARK STAR</span>
            <div class="darkstar-sub-flourish">
              <span class="flourish-line"></span>
              <span class="flourish-dot"></span>
              <span class="darkstar-sub">CONSULTING</span>
              <span class="flourish-dot"></span>
              <span class="flourish-line"></span>
            </div>
          </div>
        </div>
      </a>
    `;

    document.body.appendChild(container);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initDarkStarFooter);
  } else {
    initDarkStarFooter();
  }
})();
